class SimpleHFBF:
    def __init__(self, num_hashes, num_buckets):
        self.num_hashes = num_hashes
        self.num_buckets = num_buckets
        self.bloom_filter = [0] * num_buckets

    def _hash(self, item, seed):
        hash_value = 0
        for char in item:
            hash_value = (hash_value * seed + ord(char)) % self.num_buckets
        return hash_value

    def add(self, item):
        for i in range(self.num_hashes):
            hash_value = self._hash(item, i + 1)
            self.bloom_filter[hash_value] = 1

    def check(self, item):
        for i in range(self.num_hashes):
            hash_value = self._hash(item, i + 1)
            if self.bloom_filter[hash_value] == 0:
                return False
        return True

    def clear(self):
        self.bloom_filter = [0] * self.num_buckets

