class HFBF:
    def __init__(self, data):
        self.data = data
        self.forward_index = {}
        self.backward_index = {}
        self.build_indices()

    def build_indices(self):
        for i, item in enumerate(self.data):
            if item not in self.forward_index:
                self.forward_index[item] = []
            self.forward_index[item].append(i)

            if i not in self.backward_index:
                self.backward_index[i] = []
            self.backward_index[i].append(item)

    def forward_search(self, item):
        return self.forward_index.get(item, [])

    def backward_search(self, index):
        return self.backward_index.get(index, [])

    def yield_data(self):
        for item in self.data:
            yield item

